// THE Impact Rankings 2026 — SDG Indicator Configuration
// Source: Times Higher Education Impact Rankings methodology

export interface SubQuestion {
  index: number;
  label: string;
  maxPoints: number;
  options: { value: number; label: string }[];
}

export interface QuantMetric {
  key: string;
  label: string;
  unit: string;
}

export interface SdgIndicator {
  code: string;
  label: string;
  type: "BIBLIOMETRIC" | "QUANTITATIVE" | "QUALITATIVE";
  weightInSdg: number;
  maxScore?: number;
  subQuestions?: SubQuestion[];
  metrics?: QuantMetric[];
}

export interface SdgConfig {
  number: number;
  title: string;
  emoji: string;
  color: string;
  mandatory: boolean;
  indicators: SdgIndicator[];
}

