/** Answer shape for a QUALITATIVE indicator */
export interface QualAnswer {
  answered: "ya" | "tidak" | null;
  comment: string;
  publicLinks: string[];
  policyUpdated?: boolean;
  scopeCoverage?: "none" | "scope1_2" | "scope1_2_3_partial" | "scope1_2_3_full" | null;
  targetYear?: number | null;
}

/** Answer shape for a QUANTITATIVE indicator */
export type QuantAnswer = Record<string, string>;

/** Answer shape for a BIBLIOMETRIC indicator */
export interface BiblAnswer {
  score: number;
}

/** Full answer map for one SDG submission */
export type SdgAnswers = Record<string, QualAnswer | QuantAnswer | BiblAnswer>;
